class Solution:
    def robotWithString(self, s):
        # Simulate the stack with an explicit recompute of the suffix minimum each pop
        # (slower but obviously correct), independent of any precomputed array.
        n = len(s)
        stack = []
        out = []
        i = 0
        while i < n or stack:
            if not stack:
                stack.append(s[i])
                i += 1
                continue
            # minimum character still unread
            suffix_min = None
            for j in range(i, n):
                if suffix_min is None or s[j] < suffix_min:
                    suffix_min = s[j]
            if suffix_min is not None and stack[-1] > suffix_min:
                stack.append(s[i])
                i += 1
            else:
                out.append(stack.pop())
        return ''.join(out)

