class Solution:
    def robotWithString(self, s):
        n = len(s)
        suffix_min = [chr(127)] * (n + 1)
        for i in range(n - 1, -1, -1):
            suffix_min[i] = min(suffix_min[i + 1], s[i])
        stack = []
        out = []
        for i in range(n):
            stack.append(s[i])
            while stack and stack[-1] <= suffix_min[i + 1]:
                out.append(stack.pop())
        while stack:
            out.append(stack.pop())
        return ''.join(out)

